#include<bits/stdc++.h>
#define ll long long
using namespace std;
const int MAXN=1e5+5;
int XOR[MAXN],a[MAXN],n,l[25][2],ans=0; 
int main(void){
	scanf("%d",&n);
	for(int i=1;i<=n;++i)scanf("%d",a+i),XOR[i]=XOR[i-1]^a[i];
	for(int i=0;i<=n;++i)for(int j=21;j>=0;--j)++l[j][(XOR[i]>>j)%2];
	for(int i=0;i<21;++i)ans+=l[i][0]*l[i][1]*(1<<i);
	printf("%d",ans);
	return false;
}
